// Suponiendo que la respuesta del API está en $json
const respuesta = $json;

// Determinar la lista de órdenes (ajusta según la estructura real)
let ordenes = [];
let cliente = "desconocido";

if (Array.isArray(respuesta)) {
  // Si es un array directamente
  ordenes = respuesta;
  cliente = respuesta[0]?.cliente || "desconocido";
} else if (respuesta.orders && Array.isArray(respuesta.orders)) {
  // Si tiene una propiedad "orders"
  ordenes = respuesta.orders;
  cliente = respuesta.cliente || "desconocido";
} else if (respuesta.estado) {
  // Si es una sola orden (como en la sub-ejecución 179)
  ordenes = [respuesta];
  cliente = respuesta.nombre_cliente || "desconocido";
} else {
  // Si no se reconoce, devolver un mensaje de error
  return { mensaje: "No se pudo interpretar la respuesta del servicio." };
}

const cantidad = ordenes.length;

// Construir el mensaje base
let mensaje = `El documento ${$json.input} tiene ${cantidad} órdenes`;

if (cantidad === 0) {
  mensaje = `No se encontraron órdenes para el documento ${$json.input}.`;
} else if (cantidad === 1) {
  const estado = ordenes[0].estado || "estado desconocido";
  mensaje += `, la cual se encuentra en "${estado}".`;
} else {
  // Para múltiples órdenes, podrías listar los estados o solo mencionar la cantidad
  // Por ejemplo, listar los estados separados por comas
  const estados = ordenes.map(o => o.estado || "desconocido").join(", ");
  mensaje += `. Los estados son: ${estados}.`;
  // O simplemente: mensaje += ".";
}

// Devolver el mensaje como salida del nodo
return { mensaje };
